class SecureStrings {
  // Prevent instantiation
  SecureStrings._();

  // ============================================================
  // ENCRYPTED STRINGS (generated by encoder script)
  // ============================================================

  // RevenueCat API Key - ENCRYPTED
  // Original: "goog************************Wuym"
