    0x4C, 0x5D, 0x5C, 0x55, 0x45, 0x41, 0x1C, 0x59, 0x59, 0x19,
    0x54, 0x56, 0x4B, 0x53, 0x64, 0x51, 0x52, 0x5A, 0x5A, 0x2C,
